var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"용병 아저씨들! 살아 있어요?","JPN":"傭兵のおじさんたち！　生きてます？","ENG":"Mr. Mercenaries! Are you guys still alive?","TWN":"傭兵大叔！你們還活著嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저흰 아마 죽은 것 같지만요…… 부활 횟수가 얼마나 남았을까요?","JPN":"私たちは多分死んだみたいですけどね……復活回数はどのくらい残ってるんでしょうか？","ENG":"Although we seemed to be already dead... How many lives do you think we still have remaining?","TWN":"我們應該死了吧……還剩幾次可以復活？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"어린 녀석들이 벌써부터 재수없는 소리 마!","JPN":"ガキのくせに縁起の悪いこというなよ！","ENG":"Hey! Don’t jinx us too!","TWN":"少說那些觸霉頭的話！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그런데…… 어쩐지 처음 공격해오던 기세에 비해선 화력이 약해졌는걸?","JPN":"でも……なんか最初に攻撃してきた勢いに比べて火力が弱くなってねえか？","ENG":"Is it just me, or does it seem like their firepower has gotten weaker than when they first started attacking?","TWN":"不過……比起一開始的攻擊，現在的火力好像有減弱一點？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"맞아. 어쩐지 총알이 묘하게 느리게 날아오는 것 같기도 하고.","JPN":"そう。なんだか銃弾が妙にのろく飛んできてるみたいな。","ENG":"You have a point. It’s like the bullets are flying slower than usual.","TWN":"對啊，很奇妙，子彈飛的速度好像也比較慢。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"그러고보니 분명 토미의 머리로 날아가던 총알이 살짝 휘어져서 이상한 곳으로 날아가던데?","JPN":"そういえば確かトミーの頭に飛んでった弾がちょっと曲がって変なとこに飛んでいったぞ？","ENG":"Now that I think about it, the bullet that was flying straight towards Tommy’s head slightly curved away from him.","TWN":"聽你這麼一說，原本瞄準湯米腦袋的子彈，好像也稍微飛歪欸？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"뭔 헛소리야 그건? 총알이 눈에 보일 리 없잖아.","JPN":"なんだ、それ？　銃弾が目に見えるはずがねえだろ。","ENG":"Do you even hear what you’re saying? There’s no way you would’ve been able to see the bullet with your eyes.","TWN":"你在胡說八道什麼？肉眼怎麼可能看得到子彈！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"……과연, 그런 건가.","JPN":"……なるほど、そういうことか。","ENG":"Hmm... Could it be...","TWN":"……真是這樣嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"응? 뭔가 깨닫기라도 한 거야?","JPN":"うん？　なんか気付いたのか？","ENG":"Huh? Did you realize something?","TWN":"怎樣？你有什麼新的領悟嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그동안 우리가 겪어온 죽음의 전장이 꽤 많았지.","JPN":"これまで俺たちは結構多くの死の戦場を経験してきたな。","ENG":"We have defied death on many battlefields throughout the years.","TWN":"我們至今不知道在戰場上經歷過多少次的生死關頭。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그런 사선을 넘나드는 전투의 경험이 우리의 잠재력을 폭발 시킨 걸 수도 있어.","JPN":"そういう死線を越える戦闘経験が俺らの潜在力を爆発させたのかもしれねえ。","ENG":"All those experiences of treading the line between life and death may have awoken our potential.","TWN":"這種出生入死的戰鬥經驗，或許可以激發出我們的潛能。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"이른바…… <color=#ffd34c>각성</color>이란 녀석이지!","JPN":"いわゆる……<color=#ffd34c>覚醒</color>ってやつだ！","ENG":"Thus... We have achieved <color=#ffd34c>Awakening</color>!","TWN":"也就是所謂的……<color=#ffd34c>覺醒</color>！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"각성?","JPN":"覚醒？","ENG":"Awakening?","TWN":"覺醒？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"각성!","JPN":"覚醒！","ENG":"Awakening!","TWN":"覺醒！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"가, 각성??","JPN":"か、覚醒？？","ENG":"A-awakening??","TWN":"覺…覺醒？？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"각성! 각성!","JPN":"覚醒！　覚醒！","ENG":"Awakening! Awakening!","TWN":"覺醒！覺醒！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그래! 우린 이제 각성 용병이 된 거야!","JPN":"そうだ！　俺らはこれで覚醒傭兵になったんだよ！","ENG":"Damn straight! We’ve become Awakened mercenaries!","TWN":"一定是這樣！我們現在是覺醒傭兵！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};